function solve(chunks, queries) {

    const is_letter = (char) => char >= 'a' && char <= 'z';

    const is_word_char = (S, i) => {
        const char = S[i];
        if (is_letter(char)) {
            return true;
        }
        if (char === '-') {
            // Check for legal hyphen: must be surrounded by letters
            if (i > 0 && i < S.length - 1) {
                const prev = S[i - 1];
                const next = S[i + 1];
                if (is_letter(prev) && is_letter(next)) {
                    return true;
                }
            }
        }
        return false;
    };

    let S = chunks.join('');
    const N = S.length;
    const wordCounts = new Map();

    let i = 0;
    while (i < N) {
        if (is_word_char(S, i)) {
            // Start of a word segment
            let start = i;
            let j = i;

            // Find the end of the maximal contiguous word segment
            while (j < N && is_word_char(S, j)) {
                j++;
            }

            // Word found: S[start...j-1]
            const word = S.substring(start, j);

            // Increment count
            wordCounts.set(word, (wordCounts.get(word) || 0) + 1);

            // Move pointer past this word
            i = j;
        } else {
            // Separator character
            i++;
        }
    }

    const ans = [];
    for (const query of queries) {
        // Since queries[i] is guaranteed to be an effective word structure,
        // we just check its count.
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}

